<template>
    <div class="demo-content">
        <h1>CSS文字动画</h1>
        <div class="field">
            <div class="field-left field-border">
                <pre>
                    <code-copy :code="cssTextCode1" :btnClssName="'copy-btn'"></code-copy>
                    <code>{{cssTextCode1}}</code>
                </pre>
            </div>
            <div class="field-right field-border svg-text">
                <svg style="width:100%;height:100%" viewBox="0 0 400 400" preserveAspectRatio="xMinYMin meet">
                    <text x="20%" y="60%">CSS文字动画</text>
                </svg>
            </div>
        </div>
    </div>
</template>

<script>
import { onMounted, onUpdated, ref, onBeforeUnmount, reactive } from "vue";
import { Utils } from "../../utils/utils";
export default {
    setup() {
        const cssTextCode1 = ref(`//具体尺寸具体调整
<svg style="width:100%;height:100%" viewBox="0 0 400 400" preserveAspectRatio="xMinYMin meet">
    <text x="20%" y="60%">CSS文字动画</text>
</svg>
svg text {
    animation: stroke 5s infinite alternate;
    letter-spacing: 10px;
    font-size: 100px;
}
@keyframes stroke {
    0% {
        fill: rgba(72, 138, 20, 0);
        stroke: rgba(54, 95, 160, 1);
        stroke-dashoffset: 25%;
        stroke-dasharray: 0 50%;
        stroke-width: 1;
    }
    70% {
        fill: rgba(72, 138, 20, 0);
        stroke: rgba(54, 95, 160, 1);
        stroke-width: 3;
    }
    90%,
    100% {
        fill: rgba(72, 138, 204, 1);
        stroke: rgba(54, 95, 160, 0);
        stroke-dashoffset: -25%;
        stroke-dasharray: 50% 0;
        stroke-width: 0;
    }
}
        `);
        let constraints = reactive(null);
        let startBtn = reactive(null);
        let video = reactive(null);

        const startVideo = () => {
            window.navigator.mediaDevices.getUserMedia(constraints).then(stream => {
                video.srcObject = stream;
                window.stream = stream;
            });
        };

        onMounted(() => {
            Utils.highlightCode();
            constraints = { audio: true, video: false };
            startBtn = document.getElementById("start");
            video = document.getElementById("stream");
        });

        onUpdated(() => {
            Utils.highlightCode();
        });

        onBeforeUnmount(() => {});

        return {
            cssTextCode1,
            constraints,
            startBtn,
            video,
            startVideo
        };
    }
};
</script>

<style lang="scss" scoped>
.demo-content {
    width: 100%;
    height: 100%;
    padding: 16px;
    overflow: auto;
    display: flex;
    flex-direction: column;

    .field {
        display: flex;
        width: 100%;
        height: 400px;
        margin: 16px 0;

        .field-left {
            flex: 1;
            height: 100%;
            width: 0;

            pre {
                margin: 0;
                padding: 0;
                height: 100%;
                display: flex;
                width: 100%;
                position: relative;

                code {
                    width: 100%;
                }
            }
        }

        .field-right {
            margin-left: 16px;
            width: 50%;
            height: 100%;
            position: relative;
        }

        .field-border {
            border: 1px solid #ececec;
        }

        .svg-text {
            background: #000;

            svg text {
                animation: stroke 5s infinite alternate;
                letter-spacing: 10px;
                font-size: 100px;
            }
            @keyframes stroke {
                0% {
                    fill: rgba(72, 138, 20, 0);
                    stroke: rgba(54, 95, 160, 1);
                    stroke-dashoffset: 25%;
                    stroke-dasharray: 0 50%;
                    stroke-width: 1;
                }
                70% {
                    fill: rgba(72, 138, 20, 0);
                    stroke: rgba(54, 95, 160, 1);
                    stroke-width: 3;
                }
                90%,
                100% {
                    fill: rgba(72, 138, 204, 1);
                    stroke: rgba(54, 95, 160, 0);
                    stroke-dashoffset: -25%;
                    stroke-dasharray: 50% 0;
                    stroke-width: 0;
                }
            }
        }
    }
}
</style>
